// Command gen generates Go types for the FHIR R4 specification from the
// official JSON schema. It outputs one file per resource into r4/resources/
// and shared data types into r4/datatypes/.
package main

import (
	"bytes"
	"fmt"
	"go/format"
	"log"
	"os"
	"path/filepath"
	"sort"
	"strings"
	"unicode"

	"github.com/caucehealth/gofhir/internal/spec"
)

const (
	licenseHeader = `// Copyright 2026 the gofhir Authors
// SPDX-License-Identifier: Apache-2.0

// Code generated by cmd/gen from the FHIR R4 specification. DO NOT EDIT.
`
	datatypesDir = "r4/datatypes"
	resourcesDir = "r4/resources"
)

// primitiveGoType maps FHIR primitive type names to their Go representations.
var primitiveGoType = map[string]string{
	"string":       "string",
	"boolean":      "bool",
	"integer":      "int32",
	"decimal":      "float64",
	"uri":          "URI",
	"url":          "URL",
	"canonical":    "Canonical",
	"code":         "Code",
	"date":         "Date",
	"dateTime":     "DateTime",
	"instant":      "Instant",
	"base64Binary": "[]byte",
	"id":           "ID",
	"markdown":     "Markdown",
	"oid":          "OID",
	"positiveInt":  "uint32",
	"unsignedInt":  "uint32",
	"xhtml":        "string",
	"time":         "Time",
	"uuid":         "UUID",
	"number":       "float64",
}

// complexTypes that live in the datatypes package.
var sharedComplexTypes = map[string]bool{
	"Address": true, "Age": true, "Annotation": true, "Attachment": true,
	"CodeableConcept": true, "Coding": true, "ContactDetail": true,
	"ContactPoint": true, "Contributor": true, "Count": true,
	"DataRequirement": true, "Distance": true, "Dosage": true,
	"Duration": true, "ElementDefinition": true, "Expression": true, "Extension": true,
	"HumanName": true, "Identifier": true, "MarketingStatus": true,
	"Meta": true, "Money": true, "Narrative": true,
	"ParameterDefinition": true, "Period": true, "Population": true,
	"ProdCharacteristic": true, "ProductShelfLife": true, "Quantity": true,
	"Range": true, "Ratio": true, "Reference": true,
	"RelatedArtifact": true, "SampledData": true, "Signature": true,
	"SubstanceAmount": true, "Timing": true, "TriggerDefinition": true,
	"UsageContext": true,
}

// applyFieldOverrides fixes fields that the schema doesn't represent correctly.
// Per the FHIR spec, Extension.url is required (1..1), and integer/positiveInt
// fields should be int32/uint32 not float64.
func applyFieldOverrides(fhirSpec *spec.FHIRSpec) {
	if ext, ok := fhirSpec.ComplexTypes["Extension"]; ok {
		for _, f := range ext.Fields {
			switch f.JSONName {
			case "url":
				// Extension.url is required per FHIR spec
				f.IsRequired = true
				f.FHIRType = "uri"
				f.IsRef = true
				f.RefTarget = "uri"
			case "valueInteger":
				f.FHIRType = "integer"
				f.IsRef = false
			case "valuePositiveInt":
				f.FHIRType = "positiveInt"
				f.IsRef = false
			case "valueUnsignedInt":
				f.FHIRType = "unsignedInt"
				f.IsRef = false
			case "valueCode":
				f.IsRef = true
				f.RefTarget = "code"
			case "valueUri":
				f.IsRef = true
				f.RefTarget = "uri"
			case "valueUrl":
				f.IsRef = true
				f.RefTarget = "url"
			case "valueCanonical":
				f.IsRef = true
				f.RefTarget = "canonical"
			case "valueDate":
				f.IsRef = true
				f.RefTarget = "date"
			case "valueDateTime":
				f.IsRef = true
				f.RefTarget = "dateTime"
			case "valueInstant":
				f.IsRef = true
				f.RefTarget = "instant"
			case "valueTime":
				f.IsRef = true
				f.RefTarget = "time"
			case "valueId":
				f.IsRef = true
				f.RefTarget = "id"
			case "valueMarkdown":
				f.IsRef = true
				f.RefTarget = "markdown"
			case "valueOid":
				f.IsRef = true
				f.RefTarget = "oid"
			case "valueUuid":
				f.IsRef = true
				f.RefTarget = "uuid"
			}
		}
		if ext.Required == nil {
			ext.Required = make(map[string]bool)
		}
		ext.Required["url"] = true
	}
}

func main() {
	schemaPath := "internal/spec/fhir.schema.json"
	if len(os.Args) > 1 {
		schemaPath = os.Args[1]
	}

	log.Printf("Loading FHIR schema from %s", schemaPath)
	fhirSpec, err := spec.Load(schemaPath)
	if err != nil {
		log.Fatalf("Failed to load schema: %v", err)
	}

	log.Printf("Found %d resources, %d complex types, %d backbone elements",
		len(fhirSpec.Resources), len(fhirSpec.ComplexTypes), len(fhirSpec.BackboneElements))

	// Generate datatypes
	if err := generateDatatypes(fhirSpec); err != nil {
		log.Fatalf("Failed to generate datatypes: %v", err)
	}

	// Resources to skip (handled by dedicated packages)
	skipResources := map[string]bool{
		"Bundle": true, // handled by r4/bundle package
	}

	// Generate resources
	for _, name := range fhirSpec.ResourceNames {
		if skipResources[name] {
			continue
		}
		res := fhirSpec.Resources[name]
		if err := generateResource(res, fhirSpec); err != nil {
			log.Fatalf("Failed to generate resource %s: %v", name, err)
		}
	}

	// Generate enums file
	if err := generateEnums(fhirSpec); err != nil {
		log.Fatalf("Failed to generate enums: %v", err)
	}

	log.Println("Generation complete.")
}

func generateDatatypes(fhirSpec *spec.FHIRSpec) error {
	var buf bytes.Buffer
	buf.WriteString(licenseHeader)
	buf.WriteString("\npackage datatypes\n\n")
	buf.WriteString("import (\n\t\"fmt\"\n\t\"time\"\n)\n\n")

	// Primitive type aliases
	buf.WriteString("// --- Primitive Types ---\n\n")
	primitiveTypes := []struct {
		name, goType, desc string
	}{
		{"URI", "string", "URI represents a FHIR uri value — a Uniform Resource Identifier per RFC 3986."},
		{"URL", "string", "URL represents a FHIR url value — a Uniform Resource Locator."},
		{"Canonical", "string", "Canonical represents a FHIR canonical URL reference to a conformance resource."},
		{"Code", "string", "Code represents a FHIR code value — a string with restricted characters."},
		{"Date", "string", "Date represents a FHIR date value in the format YYYY, YYYY-MM, or YYYY-MM-DD."},
		{"DateTime", "string", "DateTime represents a FHIR dateTime value — a date with optional time and timezone."},
		{"Instant", "string", "Instant represents a FHIR instant value — an RFC3339 timestamp with mandatory timezone offset."},
		{"ID", "string", "ID represents a FHIR id value — a string matching [A-Za-z0-9\\-.]{1,64}."},
		{"Markdown", "string", "Markdown represents a FHIR markdown value — a string that may contain CommonMark."},
		{"OID", "string", "OID represents a FHIR oid value — an OID represented as a URI (urn:oid:...)."},
		{"Time", "string", "Time represents a FHIR time value in the format HH:MM:SS."},
		{"UUID", "string", "UUID represents a FHIR uuid value — a UUID represented as a URI."},
	}
	for _, pt := range primitiveTypes {
		fmt.Fprintf(&buf, "// %s\ntype %s %s\n\n", pt.desc, pt.name, pt.goType)
	}

	// ParseInstant helper
	buf.WriteString(`// ParseInstant parses a FHIR instant string (RFC3339 with mandatory timezone)
// into a time.Time value. It returns an error if the string is not a valid
// FHIR instant format.
func ParseInstant(s string) (time.Time, error) {
	t, err := time.Parse(time.RFC3339, s)
	if err != nil {
		t, err = time.Parse(time.RFC3339Nano, s)
	}
	if err != nil {
		return time.Time{}, fmt.Errorf("invalid FHIR instant %q: %w", s, err)
	}
	return t, nil
}
`)
	buf.WriteString("\n")

	// Complex types
	buf.WriteString("// --- Complex Types ---\n\n")

	// Sort complex type names for deterministic output
	var complexNames []string
	for name := range fhirSpec.ComplexTypes {
		if sharedComplexTypes[name] {
			complexNames = append(complexNames, name)
		}
	}
	sort.Strings(complexNames)

	// Apply field overrides before writing
	applyFieldOverrides(fhirSpec)

	for _, name := range complexNames {
		ct := fhirSpec.ComplexTypes[name]
		writeComplexType(&buf, ct, fhirSpec, true)
	}

	// Write backbone elements for complex types (e.g. DataRequirement_CodeFilter)
	var backboneNames []string
	for name := range fhirSpec.BackboneElements {
		parts := strings.SplitN(name, "_", 2)
		if sharedComplexTypes[parts[0]] {
			backboneNames = append(backboneNames, name)
		}
	}
	sort.Strings(backboneNames)
	for _, name := range backboneNames {
		be := fhirSpec.BackboneElements[name]
		writeComplexType(&buf, be, fhirSpec, true)
	}

	return writeGoFile(filepath.Join(datatypesDir, "datatypes_gen.go"), buf.Bytes())
}

func generateResource(res *spec.ResourceDef, fhirSpec *spec.FHIRSpec) error {
	var buf bytes.Buffer
	buf.WriteString(licenseHeader)
	buf.WriteString("\npackage resources\n\n")

	// Detect value[x] groups
	valueGroups := detectValueGroups(res.Fields)

	// Determine if fmt is needed (for Build() validation or value[x] UnmarshalJSON)
	needsFmt := len(valueGroups) > 0
	if !needsFmt {
		for _, f := range res.Fields {
			if f.IsRequired && f.JSONName != "resourceType" {
				if f.IsArray {
					needsFmt = true
					break
				}
				goType := resolveGoType(f, fhirSpec, false, "")
				if isStringLikeType(goType) || isNumericType(goType) {
					needsFmt = true
					break
				}
			}
		}
	}
	if !needsFmt {
		// Check backbone elements for value[x]
		bbPrefix := res.Name + "_"
		for bbName := range fhirSpec.BackboneElements {
			if strings.HasPrefix(bbName, bbPrefix) {
				be := fhirSpec.BackboneElements[bbName]
				if len(detectValueGroups(be.Fields)) > 0 {
					needsFmt = true
					break
				}
			}
		}
	}

	buf.WriteString("import (\n")
	buf.WriteString("\t\"encoding/json\"\n")
	if needsFmt {
		buf.WriteString("\t\"fmt\"\n")
	}
	buf.WriteString("\n")
	buf.WriteString("\tdt \"github.com/caucehealth/gofhir/r4/datatypes\"\n")
	buf.WriteString(")\n\n")

	// Write resource struct
	desc := cleanDescription(res.Description)
	fmt.Fprintf(&buf, "// %s %s\n", res.Name, desc)
	fmt.Fprintf(&buf, "type %s struct {\n", res.Name)
	fmt.Fprintf(&buf, "\t// ResourceType is the FHIR resource type name.\n")
	fmt.Fprintf(&buf, "\tResourceType string `json:\"resourceType\"` // Always %q\n", res.Name)

	writtenFields := make(map[string]bool)
	for _, f := range res.Fields {
		// Skip fields that belong to a value[x] group - they'll be handled as a union
		if group := getValueGroup(f.JSONName, valueGroups); group != "" {
			if !writtenFields[group] {
				writtenFields[group] = true
				unionTypeName := safeUnionTypeName(res.Name+exportName(group), fhirSpec)
				writeValueXField(&buf, unionTypeName, group, valueGroups[group], fhirSpec)
			}
			continue
		}
		writeStructField(&buf, f, fhirSpec, false, res.Name)
	}
	buf.WriteString("}\n\n")

	// Custom MarshalJSON
	writeResourceMarshalJSON(&buf, res, fhirSpec)

	// Custom UnmarshalJSON
	writeResourceUnmarshalJSON(&buf, res, fhirSpec)

	// Builder
	writeBuilder(&buf, res, fhirSpec, valueGroups)

	// Backbone element types for this resource
	prefix := res.Name + "_"
	var bbNames []string
	for name := range fhirSpec.BackboneElements {
		if strings.HasPrefix(name, prefix) {
			bbNames = append(bbNames, name)
		}
	}
	sort.Strings(bbNames)
	for _, name := range bbNames {
		be := fhirSpec.BackboneElements[name]
		goName := backboneGoName(name, fhirSpec)
		beValueGroups := detectValueGroups(be.Fields)

		desc := cleanDescription(be.Description)
		fmt.Fprintf(&buf, "// %s %s\n", goName, desc)
		fmt.Fprintf(&buf, "type %s struct {\n", goName)
		beWritten := make(map[string]bool)
		for _, f := range be.Fields {
			if group := getValueGroup(f.JSONName, beValueGroups); group != "" {
				if !beWritten[group] {
					beWritten[group] = true
					unionTypeName := goName + exportName(group)
					writeValueXField(&buf, unionTypeName, group, beValueGroups[group], fhirSpec)
				}
				continue
			}
			writeStructField(&buf, f, fhirSpec, false, goName)
		}
		buf.WriteString("}\n\n")

		// MarshalJSON/UnmarshalJSON for backbone elements with value[x]
		if len(beValueGroups) > 0 {
			writeBackboneMarshalJSON(&buf, goName, beValueGroups)
			writeBackboneUnmarshalJSON(&buf, goName, beValueGroups, fhirSpec)
		}

		// Value[x] union types for backbone elements
		for groupName, fields := range beValueGroups {
			unionName := goName + exportName(groupName)
			writeValueXUnion(&buf, unionName, fields, fhirSpec)
		}
	}

	// Value[x] union types for the resource
	for groupName, fields := range valueGroups {
		unionName := safeUnionTypeName(res.Name+exportName(groupName), fhirSpec)
		writeValueXUnion(&buf, unionName, fields, fhirSpec)
	}

	fileName := strings.ToLower(res.Name) + "_gen.go"
	return writeGoFile(filepath.Join(resourcesDir, fileName), buf.Bytes())
}

type enumDef struct {
	typeName string
	values   []string
	desc     string
}

func generateEnums(fhirSpec *spec.FHIRSpec) error {
	var buf bytes.Buffer
	buf.WriteString(licenseHeader)
	buf.WriteString("\npackage resources\n\n")

	seenEnums := make(map[string]*enumDef)

	for _, name := range fhirSpec.ResourceNames {
		res := fhirSpec.Resources[name]
		collectEnums(res.Name, res.Fields, seenEnums)
	}

	// Also collect from backbone elements
	var bbNames []string
	for name := range fhirSpec.BackboneElements {
		bbNames = append(bbNames, name)
	}
	sort.Strings(bbNames)
	for _, name := range bbNames {
		be := fhirSpec.BackboneElements[name]
		goName := backboneGoName(name, fhirSpec)
		collectEnums(goName, be.Fields, seenEnums)
	}

	// Sort and write
	var enumNames []string
	for name := range seenEnums {
		enumNames = append(enumNames, name)
	}
	sort.Strings(enumNames)

	for _, name := range enumNames {
		e := seenEnums[name]
		fmt.Fprintf(&buf, "// %s %s\ntype %s string\n\n", e.typeName, e.desc, e.typeName)
		fmt.Fprintf(&buf, "const (\n")
		for _, v := range e.values {
			constName := e.typeName + exportName(v)
			fmt.Fprintf(&buf, "\t// %s represents the %q value.\n", constName, v)
			fmt.Fprintf(&buf, "\t%s %s = %q\n", constName, e.typeName, v)
		}
		fmt.Fprintf(&buf, ")\n\n")
	}

	return writeGoFile(filepath.Join(resourcesDir, "enums_gen.go"), buf.Bytes())
}

func collectEnums(parentName string, fields []*spec.FieldDef, seen map[string]*enumDef) {
	for _, f := range fields {
		if len(f.Enum) == 0 {
			continue
		}
		enumTypeName := deriveEnumTypeName(parentName, f)
		if _, ok := seen[enumTypeName]; ok {
			continue
		}
		seen[enumTypeName] = &enumDef{
			typeName: enumTypeName,
			values:   f.Enum,
			desc:     fmt.Sprintf("represents allowed values for the %s field.", f.JSONName),
		}
	}
}

func deriveEnumTypeName(parentName string, f *spec.FieldDef) string {
	// Use well-known enum names where possible
	wellKnown := map[string]string{
		"gender":        "AdministrativeGender",
		"status":        parentName + "Status",
		"type":          parentName + "Type",
		"use":           parentName + "Use",
		"intent":        parentName + "Intent",
		"priority":      parentName + "Priority",
		"mode":          parentName + "Mode",
		"severity":      parentName + "Severity",
		"category":      parentName + "Category",
		"class":         parentName + "Class",
		"kind":          parentName + "Kind",
		"direction":     parentName + "Direction",
		"language":      parentName + "Language",
		"purpose":       parentName + "Purpose",
		"method":        parentName + "Method",
		"role":          parentName + "Role",
		"rank":          parentName + "Rank",
	}
	if name, ok := wellKnown[f.JSONName]; ok {
		return name
	}
	return parentName + exportName(f.JSONName)
}

// detectValueGroups finds polymorphic value[x] field groups.
// Returns map of group prefix -> fields belonging to that group.
func detectValueGroups(fields []*spec.FieldDef) map[string][]*spec.FieldDef {
	// Common value[x] prefixes
	prefixes := []string{
		"value", "effective", "onset", "abatement", "deceased",
		"serviced", "location", "medication", "reported", "occurrence",
		"timing", "product", "item", "defaultValue", "fixed", "pattern",
		"minValue", "maxValue", "example", "multipleBirth", "born", "age",
		"rate", "dose", "asNeeded", "allowed", "used", "diagnosis",
		"procedure", "definition", "entity",
	}

	groups := make(map[string][]*spec.FieldDef)

	for _, f := range fields {
		for _, prefix := range prefixes {
			if f.JSONName == prefix {
				continue // exact match, not a polymorphic variant
			}
			if strings.HasPrefix(f.JSONName, prefix) {
				suffix := f.JSONName[len(prefix):]
				if len(suffix) > 0 && unicode.IsUpper(rune(suffix[0])) {
					groups[prefix] = append(groups[prefix], f)
					break
				}
			}
		}
	}

	// Only keep groups with 2+ variants (single match is not polymorphic)
	for k, v := range groups {
		if len(v) < 2 {
			delete(groups, k)
		}
	}

	return groups
}

func getValueGroup(jsonName string, groups map[string][]*spec.FieldDef) string {
	for prefix := range groups {
		if jsonName == prefix {
			continue
		}
		if strings.HasPrefix(jsonName, prefix) {
			suffix := jsonName[len(prefix):]
			if len(suffix) > 0 && unicode.IsUpper(rune(suffix[0])) {
				return prefix
			}
		}
	}
	return ""
}

func writeValueXField(buf *bytes.Buffer, unionTypeName string, groupPrefix string, fields []*spec.FieldDef, fhirSpec *spec.FHIRSpec) {
	desc := fields[0].Description
	if desc == "" {
		desc = "is a polymorphic value field."
	}
	fieldName := exportName(groupPrefix)
	fmt.Fprintf(buf, "\t// %s %s\n", fieldName, cleanDescription(desc))
	fmt.Fprintf(buf, "\t%s *%s `json:\"-\"` // polymorphic\n", fieldName, unionTypeName)
}

func writeValueXUnion(buf *bytes.Buffer, typeName string, fields []*spec.FieldDef, fhirSpec *spec.FHIRSpec) {
	fmt.Fprintf(buf, "// %s represents a polymorphic choice type in FHIR.\n", typeName)
	fmt.Fprintf(buf, "type %s struct {\n", typeName)
	for _, f := range fields {
		goType := resolveGoType(f, fhirSpec, false, "")
		// Make pointer for union fields
		if !strings.HasPrefix(goType, "*") && !strings.HasPrefix(goType, "[]") {
			goType = "*" + goType
		}
		fieldName := getValueXFieldName(f.JSONName)
		fmt.Fprintf(buf, "\t%s %s `json:\"%s,omitempty\"` // %s\n",
			fieldName, goType, f.JSONName, cleanDescription(f.Description))
	}
	buf.WriteString("}\n\n")

	// MarshalJSON for the union type
	fmt.Fprintf(buf, "// MarshalJSON implements the json.Marshaler interface for %s.\n", typeName)
	fmt.Fprintf(buf, "func (v %s) MarshalJSON() ([]byte, error) {\n", typeName)
	buf.WriteString("\tm := make(map[string]interface{})\n")
	for _, f := range fields {
		fieldName := getValueXFieldName(f.JSONName)
		fmt.Fprintf(buf, "\tif v.%s != nil {\n", fieldName)
		fmt.Fprintf(buf, "\t\tm[%q] = v.%s\n", f.JSONName, fieldName)
		fmt.Fprintf(buf, "\t}\n")
	}
	buf.WriteString("\treturn json.Marshal(m)\n")
	buf.WriteString("}\n\n")

	// UnmarshalJSON for the union type
	fmt.Fprintf(buf, "// UnmarshalJSON implements the json.Unmarshaler interface for %s.\n", typeName)
	fmt.Fprintf(buf, "func (v *%s) UnmarshalJSON(data []byte) error {\n", typeName)
	buf.WriteString("\tvar raw map[string]json.RawMessage\n")
	buf.WriteString("\tif err := json.Unmarshal(data, &raw); err != nil {\n")
	buf.WriteString("\t\treturn err\n")
	buf.WriteString("\t}\n")
	for _, f := range fields {
		fieldName := getValueXFieldName(f.JSONName)
		goType := resolveGoType(f, fhirSpec, false, "")
		isSlice := strings.HasPrefix(goType, "[]")
		if strings.HasPrefix(goType, "*") {
			goType = goType[1:]
		}
		fmt.Fprintf(buf, "\tif d, ok := raw[%q]; ok {\n", f.JSONName)
		fmt.Fprintf(buf, "\t\tvar val %s\n", goType)
		fmt.Fprintf(buf, "\t\tif err := json.Unmarshal(d, &val); err != nil {\n")
		fmt.Fprintf(buf, "\t\t\treturn fmt.Errorf(\"unmarshaling %s: %%w\", err)\n", f.JSONName)
		fmt.Fprintf(buf, "\t\t}\n")
		if isSlice {
			fmt.Fprintf(buf, "\t\tv.%s = val\n", fieldName)
		} else {
			fmt.Fprintf(buf, "\t\tv.%s = &val\n", fieldName)
		}
		fmt.Fprintf(buf, "\t}\n")
	}
	buf.WriteString("\treturn nil\n")
	buf.WriteString("}\n\n")
}

func getValueXFieldName(jsonName string) string {
	for _, prefix := range []string{
		"value", "effective", "onset", "abatement", "deceased",
		"serviced", "location", "medication", "reported", "occurrence",
		"timing", "product", "item", "defaultValue", "fixed", "pattern",
		"minValue", "maxValue", "example", "multipleBirth", "born", "age",
		"rate", "dose", "asNeeded", "allowed", "used", "diagnosis",
		"procedure", "definition", "entity",
	} {
		if strings.HasPrefix(jsonName, prefix) && len(jsonName) > len(prefix) {
			suffix := jsonName[len(prefix):]
			if unicode.IsUpper(rune(suffix[0])) {
				return exportName(suffix)
			}
		}
	}
	return exportName(jsonName)
}

func writeStructField(buf *bytes.Buffer, f *spec.FieldDef, fhirSpec *spec.FHIRSpec, isDatatypes bool, parentName string) {
	goType := resolveGoType(f, fhirSpec, isDatatypes, parentName)
	jsonTag := f.JSONName

	if f.IsArray {
		omit := ",omitempty"
		fmt.Fprintf(buf, "\t// %s %s\n", exportName(f.JSONName), cleanDescription(f.Description))
		fmt.Fprintf(buf, "\t%s %s `json:\"%s%s\"`\n", exportName(f.JSONName), goType, jsonTag, omit)
	} else if f.IsRequired {
		fmt.Fprintf(buf, "\t// %s %s\n", exportName(f.JSONName), cleanDescription(f.Description))
		fmt.Fprintf(buf, "\t%s %s `json:\"%s\"`\n", exportName(f.JSONName), goType, jsonTag)
	} else {
		ptr := goType
		if !strings.HasPrefix(ptr, "*") && !strings.HasPrefix(ptr, "[]") {
			ptr = "*" + ptr
		}
		fmt.Fprintf(buf, "\t// %s %s\n", exportName(f.JSONName), cleanDescription(f.Description))
		fmt.Fprintf(buf, "\t%s %s `json:\"%s,omitempty\"`\n", exportName(f.JSONName), ptr, jsonTag)
	}
}

func resolveGoType(f *spec.FieldDef, fhirSpec *spec.FHIRSpec, isDatatypes bool, parentName string) string {
	var baseType string

	if len(f.Enum) > 0 {
		if parentName != "" {
			// Use the enum type name in the resources package
			baseType = deriveEnumTypeName(parentName, f)
		} else {
			baseType = "string"
		}
	} else if f.IsRef {
		baseType = resolveRefType(f.RefTarget, fhirSpec, isDatatypes)
	} else if goType, ok := primitiveGoType[f.FHIRType]; ok {
		if !isDatatypes && isCustomPrimitive(goType) {
			baseType = "dt." + goType
		} else {
			baseType = goType
		}
	} else {
		baseType = f.FHIRType
	}

	if f.IsArray {
		return "[]" + baseType
	}
	return baseType
}

func resolveRefType(target string, fhirSpec *spec.FHIRSpec, isDatatypes bool) string {
	// ResourceList is the "contained" array — use json.RawMessage
	if target == "ResourceList" {
		return "json.RawMessage"
	}

	// Check if it's a primitive
	if goType, ok := primitiveGoType[target]; ok {
		if !isDatatypes && isCustomPrimitive(goType) {
			return "dt." + goType
		}
		return goType
	}

	// Check if it's a shared complex type
	if sharedComplexTypes[target] {
		if isDatatypes {
			return target
		}
		return "dt." + target
	}

	// Check if it's a backbone element
	if _, ok := fhirSpec.BackboneElements[target]; ok {
		return backboneGoName(target, fhirSpec)
	}

	// Check if it's a resource
	if _, ok := fhirSpec.Resources[target]; ok {
		return target
	}

	// Fallback
	goName := strings.ReplaceAll(target, "_", "")
	return goName
}

// safeUnionTypeName returns a union type name that doesn't collide with resource names.
func safeUnionTypeName(name string, fhirSpec *spec.FHIRSpec) string {
	if _, ok := fhirSpec.Resources[name]; ok {
		return name + "Choice"
	}
	return name
}

// backboneGoName returns the Go type name for a backbone element,
// handling collisions with resource names.
func backboneGoName(name string, fhirSpec *spec.FHIRSpec) string {
	goName := strings.ReplaceAll(name, "_", "")
	// If this collides with a resource name, prefix with parent
	if _, ok := fhirSpec.Resources[goName]; ok {
		// e.g. ChargeItem_Definition → ChargeItemChargeItemDefinition? No, better: add "Component" suffix
		// Actually use the full concatenated name which already avoids collision
		// The problem is ChargeItem has backbone "ChargeItem_Definition" → "ChargeItemDefinition"
		// which collides with the "ChargeItemDefinition" resource.
		// Solution: suffix with "BackboneElement" to disambiguate.
		goName = goName + "Component"
	}
	return goName
}

func isCustomPrimitive(goType string) bool {
	switch goType {
	case "URI", "URL", "Canonical", "Code", "Date", "DateTime", "Instant",
		"ID", "Markdown", "OID", "Time", "UUID":
		return true
	}
	return false
}

func writeBackboneMarshalJSON(buf *bytes.Buffer, typeName string, valueGroups map[string][]*spec.FieldDef) {
	fmt.Fprintf(buf, "// MarshalJSON implements the json.Marshaler interface for %s.\n", typeName)
	fmt.Fprintf(buf, "func (r %s) MarshalJSON() ([]byte, error) {\n", typeName)
	fmt.Fprintf(buf, "\ttype Alias %s\n", typeName)
	buf.WriteString("\tdata, err := json.Marshal((Alias)(r))\n")
	buf.WriteString("\tif err != nil {\n")
	buf.WriteString("\t\treturn nil, err\n")
	buf.WriteString("\t}\n")
	buf.WriteString("\tvar m map[string]json.RawMessage\n")
	buf.WriteString("\tif err := json.Unmarshal(data, &m); err != nil {\n")
	buf.WriteString("\t\treturn nil, err\n")
	buf.WriteString("\t}\n")
	for prefix := range valueGroups {
		fieldName := exportName(prefix)
		fmt.Fprintf(buf, "\tif r.%s != nil {\n", fieldName)
		fmt.Fprintf(buf, "\t\tvData, err := json.Marshal(r.%s)\n", fieldName)
		fmt.Fprintf(buf, "\t\tif err != nil {\n")
		fmt.Fprintf(buf, "\t\t\treturn nil, err\n")
		fmt.Fprintf(buf, "\t\t}\n")
		buf.WriteString("\t\tvar vm map[string]json.RawMessage\n")
		buf.WriteString("\t\tif err := json.Unmarshal(vData, &vm); err != nil {\n")
		buf.WriteString("\t\t\treturn nil, err\n")
		buf.WriteString("\t\t}\n")
		buf.WriteString("\t\tfor k, v := range vm {\n")
		buf.WriteString("\t\t\tm[k] = v\n")
		buf.WriteString("\t\t}\n")
		fmt.Fprintf(buf, "\t}\n")
	}
	buf.WriteString("\treturn json.Marshal(m)\n")
	buf.WriteString("}\n\n")
}

func writeBackboneUnmarshalJSON(buf *bytes.Buffer, typeName string, valueGroups map[string][]*spec.FieldDef, fhirSpec *spec.FHIRSpec) {
	fmt.Fprintf(buf, "// UnmarshalJSON implements the json.Unmarshaler interface for %s.\n", typeName)
	fmt.Fprintf(buf, "func (r *%s) UnmarshalJSON(data []byte) error {\n", typeName)
	fmt.Fprintf(buf, "\ttype Alias %s\n", typeName)
	buf.WriteString("\tvar alias Alias\n")
	buf.WriteString("\tif err := json.Unmarshal(data, &alias); err != nil {\n")
	buf.WriteString("\t\treturn err\n")
	buf.WriteString("\t}\n")
	fmt.Fprintf(buf, "\t*r = %s(alias)\n", typeName)
	for prefix, fields := range valueGroups {
		fieldName := exportName(prefix)
		unionTypeName := typeName + exportName(prefix)
		fmt.Fprintf(buf, "\tvar %sVal %s\n", prefix, unionTypeName)
		fmt.Fprintf(buf, "\tif err := %sVal.UnmarshalJSON(data); err != nil {\n", prefix)
		buf.WriteString("\t\treturn err\n")
		buf.WriteString("\t}\n")
		fmt.Fprintf(buf, "\tif ")
		for i, f := range fields {
			fn := getValueXFieldName(f.JSONName)
			if i > 0 {
				buf.WriteString(" || ")
			}
			fmt.Fprintf(buf, "%sVal.%s != nil", prefix, fn)
		}
		buf.WriteString(" {\n")
		fmt.Fprintf(buf, "\t\tr.%s = &%sVal\n", fieldName, prefix)
		buf.WriteString("\t}\n")
	}
	buf.WriteString("\treturn nil\n")
	buf.WriteString("}\n\n")
}

func writeResourceMarshalJSON(buf *bytes.Buffer, res *spec.ResourceDef, fhirSpec *spec.FHIRSpec) {
	fmt.Fprintf(buf, "// MarshalJSON implements the json.Marshaler interface for %s.\n", res.Name)
	fmt.Fprintf(buf, "func (r %s) MarshalJSON() ([]byte, error) {\n", res.Name)
	fmt.Fprintf(buf, "\tr.ResourceType = %q\n", res.Name)
	fmt.Fprintf(buf, "\ttype Alias %s\n", res.Name)

	// Check if there are value[x] groups
	valueGroups := detectValueGroups(res.Fields)
	if len(valueGroups) == 0 {
		buf.WriteString("\treturn json.Marshal((Alias)(r))\n")
	} else {
		buf.WriteString("\tdata, err := json.Marshal((Alias)(r))\n")
		buf.WriteString("\tif err != nil {\n")
		buf.WriteString("\t\treturn nil, err\n")
		buf.WriteString("\t}\n")
		buf.WriteString("\t// Merge polymorphic fields into the JSON object\n")
		buf.WriteString("\tvar m map[string]json.RawMessage\n")
		buf.WriteString("\tif err := json.Unmarshal(data, &m); err != nil {\n")
		buf.WriteString("\t\treturn nil, err\n")
		buf.WriteString("\t}\n")
		for prefix := range valueGroups {
			fieldName := exportName(prefix)
			fmt.Fprintf(buf, "\tif r.%s != nil {\n", fieldName)
			fmt.Fprintf(buf, "\t\tvData, err := json.Marshal(r.%s)\n", fieldName)
			fmt.Fprintf(buf, "\t\tif err != nil {\n")
			fmt.Fprintf(buf, "\t\t\treturn nil, err\n")
			fmt.Fprintf(buf, "\t\t}\n")
			buf.WriteString("\t\tvar vm map[string]json.RawMessage\n")
			buf.WriteString("\t\tif err := json.Unmarshal(vData, &vm); err != nil {\n")
			buf.WriteString("\t\t\treturn nil, err\n")
			buf.WriteString("\t\t}\n")
			buf.WriteString("\t\tfor k, v := range vm {\n")
			buf.WriteString("\t\t\tm[k] = v\n")
			buf.WriteString("\t\t}\n")
			fmt.Fprintf(buf, "\t}\n")
		}
		buf.WriteString("\treturn json.Marshal(m)\n")
	}
	buf.WriteString("}\n\n")
}

func writeResourceUnmarshalJSON(buf *bytes.Buffer, res *spec.ResourceDef, fhirSpec *spec.FHIRSpec) {
	valueGroups := detectValueGroups(res.Fields)

	fmt.Fprintf(buf, "// UnmarshalJSON implements the json.Unmarshaler interface for %s.\n", res.Name)
	fmt.Fprintf(buf, "func (r *%s) UnmarshalJSON(data []byte) error {\n", res.Name)
	fmt.Fprintf(buf, "\ttype Alias %s\n", res.Name)

	if len(valueGroups) == 0 {
		buf.WriteString("\tvar alias Alias\n")
		buf.WriteString("\tif err := json.Unmarshal(data, &alias); err != nil {\n")
		buf.WriteString("\t\treturn err\n")
		buf.WriteString("\t}\n")
		buf.WriteString("\t*r = ")
		fmt.Fprintf(buf, "%s(alias)\n", res.Name)
		buf.WriteString("\treturn nil\n")
	} else {
		buf.WriteString("\tvar alias Alias\n")
		buf.WriteString("\tif err := json.Unmarshal(data, &alias); err != nil {\n")
		buf.WriteString("\t\treturn err\n")
		buf.WriteString("\t}\n")
		fmt.Fprintf(buf, "\t*r = %s(alias)\n", res.Name)
		buf.WriteString("\t// Unmarshal polymorphic fields\n")
		for prefix, fields := range valueGroups {
			fieldName := exportName(prefix)
			unionTypeName := safeUnionTypeName(res.Name+exportName(prefix), fhirSpec)
			fmt.Fprintf(buf, "\tvar %sVal %s\n", prefix, unionTypeName)
			fmt.Fprintf(buf, "\tif err := %sVal.UnmarshalJSON(data); err != nil {\n", prefix)
			buf.WriteString("\t\treturn err\n")
			buf.WriteString("\t}\n")
			// Check if any field is set
			fmt.Fprintf(buf, "\tif ")
			for i, f := range fields {
				fn := getValueXFieldName(f.JSONName)
				if i > 0 {
					buf.WriteString(" || ")
				}
				fmt.Fprintf(buf, "%sVal.%s != nil", prefix, fn)
			}
			buf.WriteString(" {\n")
			fmt.Fprintf(buf, "\t\tr.%s = &%sVal\n", fieldName, prefix)
			buf.WriteString("\t}\n")
		}
		buf.WriteString("\treturn nil\n")
	}
	buf.WriteString("}\n\n")
}

func writeBuilder(buf *bytes.Buffer, res *spec.ResourceDef, fhirSpec *spec.FHIRSpec, valueGroups map[string][]*spec.FieldDef) {
	builderName := res.Name + "Builder"

	fmt.Fprintf(buf, "// %s provides a fluent API for constructing %s resources.\n", builderName, res.Name)
	fmt.Fprintf(buf, "type %s struct {\n", builderName)
	fmt.Fprintf(buf, "\tresource %s\n", res.Name)
	buf.WriteString("}\n\n")

	// Constructor
	fmt.Fprintf(buf, "// New%s creates a new %s for building a %s resource.\n", res.Name, builderName, res.Name)
	fmt.Fprintf(buf, "func New%s() *%s {\n", res.Name, builderName)
	fmt.Fprintf(buf, "\treturn &%s{resource: %s{ResourceType: %q}}\n", builderName, res.Name, res.Name)
	buf.WriteString("}\n\n")

	// Convenience methods for common fields
	convenienceFields := writeConvenienceBuilderMethods(buf, res, builderName, fhirSpec, valueGroups)

	// Generic setter for each field (skip those covered by convenience methods)
	writtenFields := make(map[string]bool)
	for _, f := range res.Fields {
		if group := getValueGroup(f.JSONName, valueGroups); group != "" {
			if !writtenFields[group] {
				writtenFields[group] = true
				writeValueXBuilderMethod(buf, builderName, res.Name, group, valueGroups[group], fhirSpec, convenienceFields)
			}
			continue
		}
		methodName := "With" + exportName(f.JSONName)
		if convenienceFields[methodName] {
			continue
		}
		writeBuilderSetter(buf, builderName, f, fhirSpec, res.Name)
	}

	// Build method
	fmt.Fprintf(buf, "// Build returns the constructed %s. It returns an error if any required\n", res.Name)
	fmt.Fprintf(buf, "// field (cardinality 1..1) is not set.\n")
	fmt.Fprintf(buf, "func (b *%s) Build() (*%s, error) {\n", builderName, res.Name)

	// Collect actionable required field checks
	type requiredCheck struct {
		fieldName string
		jsonName  string
		checkExpr string
	}
	var checks []requiredCheck
	for _, f := range res.Fields {
		if !f.IsRequired || f.JSONName == "resourceType" {
			continue
		}
		goFieldName := exportName(f.JSONName)
		if f.IsArray {
			checks = append(checks, requiredCheck{goFieldName, f.JSONName,
				fmt.Sprintf("len(b.resource.%s) == 0", goFieldName)})
		} else {
			goType := resolveGoType(f, fhirSpec, false, "")
			if isStringLikeType(goType) {
				checks = append(checks, requiredCheck{goFieldName, f.JSONName,
					fmt.Sprintf("b.resource.%s == \"\"", goFieldName)})
			} else if isNumericType(goType) {
				checks = append(checks, requiredCheck{goFieldName, f.JSONName,
					fmt.Sprintf("b.resource.%s == 0", goFieldName)})
			}
			// Skip struct types — zero-value struct is valid in Go
		}
	}
	if len(checks) > 0 {
		buf.WriteString("\tvar missing []string\n")
		for _, c := range checks {
			fmt.Fprintf(buf, "\tif %s {\n", c.checkExpr)
			fmt.Fprintf(buf, "\t\tmissing = append(missing, %q)\n", c.jsonName)
			buf.WriteString("\t}\n")
		}
		buf.WriteString("\tif len(missing) > 0 {\n")
		fmt.Fprintf(buf, "\t\treturn nil, fmt.Errorf(\"%s: required fields missing: %%v\", missing)\n", res.Name)
		buf.WriteString("\t}\n")
	}

	buf.WriteString("\tr := b.resource\n")
	buf.WriteString("\treturn &r, nil\n")
	buf.WriteString("}\n\n")
}

func isStringLikeType(goType string) bool {
	switch goType {
	case "string", "dt.Code", "dt.URI", "dt.URL", "dt.ID", "dt.Date",
		"dt.DateTime", "dt.Instant", "dt.Markdown", "dt.OID", "dt.Canonical",
		"dt.Time", "dt.UUID":
		return true
	}
	return false
}

func isNumericType(goType string) bool {
	switch goType {
	case "int32", "uint32", "float64", "bool":
		return true
	}
	return false
}

func writeConvenienceBuilderMethods(buf *bytes.Buffer, res *spec.ResourceDef, builderName string, fhirSpec *spec.FHIRSpec, valueGroups map[string][]*spec.FieldDef) map[string]bool {
	methods := make(map[string]bool)
	switch res.Name {
	case "Patient":
		buf.WriteString(patientConvenienceMethods(builderName))
		methods["WithName"] = true
		methods["WithBirthDate"] = true
		methods["WithGender"] = true
	case "Observation":
		buf.WriteString(observationConvenienceMethods(builderName))
		methods["WithStatus"] = true
		methods["WithCode"] = true
		methods["WithSubject"] = true
	case "Encounter":
		buf.WriteString(encounterConvenienceMethods(builderName))
		methods["WithStatus"] = true
		methods["WithClass"] = true
		methods["WithSubject"] = true
	case "Practitioner":
		buf.WriteString(practitionerConvenienceMethods(builderName))
		methods["WithName"] = true
	case "Condition":
		buf.WriteString(conditionConvenienceMethods(builderName))
		methods["WithCode"] = true
		methods["WithSubject"] = true
	case "DiagnosticReport":
		buf.WriteString(diagnosticReportConvenienceMethods(builderName))
		methods["WithStatus"] = true
		methods["WithCode"] = true
		methods["WithSubject"] = true
	case "MedicationRequest":
		buf.WriteString(medicationRequestConvenienceMethods(builderName))
		methods["WithStatus"] = true
		methods["WithIntent"] = true
		methods["WithSubject"] = true
		methods["WithMedicationCodeableConcept"] = true
	}
	return methods
}

