func writeValueXBuilderMethod(buf *bytes.Buffer, builderName, resName, prefix string, fields []*spec.FieldDef, fhirSpec *spec.FHIRSpec, skipMethods map[string]bool) {
	unionTypeName := safeUnionTypeName(resName+exportName(prefix), fhirSpec)
	fieldName := exportName(prefix)

	for _, f := range fields {
		goType := resolveGoType(f, fhirSpec, false, "")
		isSlice := strings.HasPrefix(goType, "[]")
		if strings.HasPrefix(goType, "*") {
			goType = goType[1:]
		}
		valFieldName := getValueXFieldName(f.JSONName)
		methodName := "With" + exportName(f.JSONName)

		if skipMethods[methodName] {
			continue
		}

		fmt.Fprintf(buf, "// %s sets the %s polymorphic field.\n", methodName, f.JSONName)
		fmt.Fprintf(buf, "func (b *%s) %s(v %s) *%s {\n", builderName, methodName, goType, builderName)
		fmt.Fprintf(buf, "\tif b.resource.%s == nil {\n", fieldName)
		fmt.Fprintf(buf, "\t\tb.resource.%s = &%s{}\n", fieldName, unionTypeName)
		fmt.Fprintf(buf, "\t}\n")
		if isSlice {
			fmt.Fprintf(buf, "\tb.resource.%s.%s = v\n", fieldName, valFieldName)
		} else {
			fmt.Fprintf(buf, "\tb.resource.%s.%s = &v\n", fieldName, valFieldName)
		}
		fmt.Fprintf(buf, "\treturn b\n")
		fmt.Fprintf(buf, "}\n\n")
	}
}

func writeBuilderSetter(buf *bytes.Buffer, builderName string, f *spec.FieldDef, fhirSpec *spec.FHIRSpec, parentName string) {
	goType := resolveGoType(f, fhirSpec, false, parentName)
	goFieldName := exportName(f.JSONName)
	methodName := "With" + goFieldName

	if f.IsArray {
		// For arrays, allow adding single items
		elemType := goType[2:] // strip []
		fmt.Fprintf(buf, "// %s adds an item to the %s field.\n", methodName, f.JSONName)
		fmt.Fprintf(buf, "func (b *%s) %s(v %s) *%s {\n", builderName, methodName, elemType, builderName)
		fmt.Fprintf(buf, "\tb.resource.%s = append(b.resource.%s, v)\n", goFieldName, goFieldName)
		buf.WriteString("\treturn b\n")
		buf.WriteString("}\n\n")
	} else if f.IsRequired {
		fmt.Fprintf(buf, "// %s sets the %s field.\n", methodName, f.JSONName)
		fmt.Fprintf(buf, "func (b *%s) %s(v %s) *%s {\n", builderName, methodName, goType, builderName)
		fmt.Fprintf(buf, "\tb.resource.%s = v\n", goFieldName)
		buf.WriteString("\treturn b\n")
		buf.WriteString("}\n\n")
	} else {
		// Optional fields - take value, set pointer
		if strings.HasPrefix(goType, "*") || strings.HasPrefix(goType, "[]") {
			fmt.Fprintf(buf, "// %s sets the %s field.\n", methodName, f.JSONName)
			fmt.Fprintf(buf, "func (b *%s) %s(v %s) *%s {\n", builderName, methodName, goType, builderName)
			fmt.Fprintf(buf, "\tb.resource.%s = v\n", goFieldName)
		} else {
			fmt.Fprintf(buf, "// %s sets the %s field.\n", methodName, f.JSONName)
			fmt.Fprintf(buf, "func (b *%s) %s(v %s) *%s {\n", builderName, methodName, goType, builderName)
			fmt.Fprintf(buf, "\tb.resource.%s = &v\n", goFieldName)
		}
		buf.WriteString("\treturn b\n")
		buf.WriteString("}\n\n")
	}
}

func writeComplexType(buf *bytes.Buffer, ct *spec.ComplexTypeDef, fhirSpec *spec.FHIRSpec, isDatatypes bool) {
	goName := strings.ReplaceAll(ct.Name, "_", "")
	desc := cleanDescription(ct.Description)
	fmt.Fprintf(buf, "// %s %s\n", goName, desc)
	fmt.Fprintf(buf, "type %s struct {\n", goName)
	for _, f := range ct.Fields {
		writeStructField(buf, f, fhirSpec, isDatatypes, "")
	}
	buf.WriteString("}\n\n")
}

func writeGoFile(path string, content []byte) error {
	formatted, err := format.Source(content)
	if err != nil {
		// Write unformatted for debugging
		_ = os.MkdirAll(filepath.Dir(path), 0o755)
		_ = os.WriteFile(path, content, 0o644)
		return fmt.Errorf("formatting %s: %w\nContent written unformatted for debugging", path, err)
	}
	if err := os.MkdirAll(filepath.Dir(path), 0o755); err != nil {
		return err
	}
	return os.WriteFile(path, formatted, 0o644)
}

func exportName(s string) string {
	if s == "" {
		return ""
	}
	// Replace operator symbols with readable names (longest first to avoid partial matches)
	opReplacements := []struct{ old, repl string }{
		{"!=", "NotEqual"},
		{"<=", "LessOrEqual"},
		{">=", "GreaterOrEqual"},
		{"<", "LessThan"},
		{">", "GreaterThan"},
		{"=", "Equal"},
	}
	for _, r := range opReplacements {
		if strings.Contains(s, r.old) {
			s = strings.Replace(s, r.old, r.repl, 1)
			break
		}
	}
	// Strip characters invalid in Go identifiers
	var out []rune
	for _, r := range s {
		if unicode.IsLetter(r) || unicode.IsDigit(r) || r == '_' {
			out = append(out, r)
		}
	}
	if len(out) == 0 {
		return "Value"
	}
	// Ensure starts with a letter
	if !unicode.IsLetter(out[0]) {
		out = append([]rune{'V'}, out...)
	}
	out[0] = unicode.ToUpper(out[0])
	return string(out)
}

func cleanDescription(s string) string {
	s = strings.ReplaceAll(s, "\n", " ")
	s = strings.ReplaceAll(s, "\r", "")
	s = strings.TrimSpace(s)
	if len(s) > 200 {
		s = s[:197] + "..."
	}
	if s == "" {
		return "is defined by the FHIR specification."
	}
	return s
}
